import{_ as o,o as d,c as a,ai as c,aj as r,ak as t,al as s,am as p,an as i,ao as l}from"./chunks/framework.C-hzIKVg.js";const I=JSON.parse('{"title":"ドライバ・ツールのインストール","description":"","frontmatter":{},"headers":[],"relativePath":"prepare/driver-setup.md","filePath":"prepare/driver-setup.md"}'),n={name:"prepare/driver-setup.md"};function h(f,e,u,S,m,_){return d(),a("div",null,[...e[0]||(e[0]=[c('<h1 id="ドライバ・ツールのインストール" tabindex="-1">ドライバ・ツールのインストール <a class="header-anchor" href="#ドライバ・ツールのインストール" aria-label="Permalink to “ドライバ・ツールのインストール”">​</a></h1><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>ここからの手順は、使いたいPCとUSBメモリで一度だけ行う必要があります。</p></div><p>リソグラフで印刷するために必要なドライバやツールのインストール方法を説明します。</p><h2 id="ドライバー等のダウンロード" tabindex="-1">ドライバー等のダウンロード <a class="header-anchor" href="#ドライバー等のダウンロード" aria-label="Permalink to “ドライバー等のダウンロード”">​</a></h2><p>PCで、使いたい機種のプリンタードライバーとユーティリティーソフトをダウンロードしてください。<br> プリンタードライバーは機種ごとに異なり、ユーティリティーソフトは機種によらず共通です。</p><h3 id="sf625ii-生徒会室の新しい方" tabindex="-1">SF625Ⅱ(生徒会室の新しい方) <a class="header-anchor" href="#sf625ii-生徒会室の新しい方" aria-label="Permalink to “SF625Ⅱ(生徒会室の新しい方)”">​</a></h3><p>下記のリンクより、プリンタードライバー<code>RISO Printer Driver for SF9II/SF6II/SF5II Series</code>と、ユーティリティーソフト<code>RISO Utility Software</code>をダウンロードしてください。</p><p><a href="https://www.riso.co.jp/dl/sf2_dvd119m_whql.html" target="_blank" rel="noreferrer">ダウンロード SF9II/SF6II/SF5II Series</a></p><h3 id="sd5430-生徒会室の古い方" tabindex="-1">SD5430(生徒会室の古い方) <a class="header-anchor" href="#sd5430-生徒会室の古い方" aria-label="Permalink to “SD5430(生徒会室の古い方)”">​</a></h3><p>下記のリンクより、プリンタードライバー<code>RISO PRINTER DRIVER for SD5x30 Series</code>と、ユーティリティーソフト<code>RISO Utility Software</code>をダウンロードしてください。</p><p><a href="https://www.riso.co.jp/dl/sd53_cd108f_win.html" target="_blank" rel="noreferrer">ダウンロード SD5x30 Series</a></p><h3 id="その他の機種" tabindex="-1">その他の機種 <a class="header-anchor" href="#その他の機種" aria-label="Permalink to “その他の機種”">​</a></h3><p>使いたいリソグラフの型番が上記にない場合は、<a href="https://www.riso.co.jp/dl/index.html" target="_blank" rel="noreferrer">プリンタードライバー・ユーティリティソフト・マニュアルのダウンロード</a>からドライバやツールを探すことで、同様にダウンロードできる可能性があります。</p><h2 id="ドライバーのインストール" tabindex="-1">ドライバーのインストール <a class="header-anchor" href="#ドライバーのインストール" aria-label="Permalink to “ドライバーのインストール”">​</a></h2><p>ダウンロードしたドライバーのZIPファイル(<code>sf2_dvd119m.zip</code>か<code>SD5x30_CD108f.zip</code>)を、右クリックして「すべて展開」を選択し、解凍してください。</p><p>解凍してできたフォルダの中にある(2階層中にある)<code>Windows 64-bit</code>フォルダの中にある<code>Setup.exe</code>をダブルクリックして、インストーラーを起動してください。 <img src="'+r+'" alt="Setup.exe"></p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>現在ほとんどのPCが64ビットOSであるため、<code>Windows 64-bit</code>と書きましたが、32ビットOSを使用している場合は、<code>Windows 32-bit</code>のドライバーをインストールしてください。<br> わからなければ、上記の通り<code>Windows 64-bit</code>のドライバーをインストールしてみてください。</p></div><p>インストーラーに従って<code>OK</code>、<code>次へ</code>をクリックして進めます。</p><p><code>お使いのパソコンとプリンタを接続する方法を選択します。</code>の画面では、<code>USBメモリへ出力する</code>を選択して、<code>次へ</code>をクリックしてください。 <img src="'+t+'" alt="接続方法選択"></p><p><code>インストールするドライバを選択します</code>の画面では、使いたい機種<code>RISO SF 6x5ⅡSeries(USB)</code>か<code>RISO SD 5x30 Series(USBメモリ)</code>を選択して、<code>次へ</code>をクリックしてください。 <img src="'+s+'" alt="ドライバ選択"></p><p><code>プリンタ名を入力します。</code>の画面では、デフォルトのまま、<code>次へ</code>をクリックしてください。</p><p><code>プリンタドライバのインストールの準備ができました。</code>の画面では、<code>インストール</code>をクリックしてください。</p><p><code>このデバイスソフトウェアをインストールしますか?</code>というアラートが表示されるので、<code>インストール</code>をクリックしてください。 <img src="'+p+'" alt="セキュリティ"></p><p>完了した旨が表示されたら、<code>OK</code>をクリックしてください。 画面に従い、<code>今すぐに再起動する</code>を選択してPCを再起動するか、後で自分で再起動してください。</p><h2 id="ユーティリティーソフトのインストール" tabindex="-1">ユーティリティーソフトのインストール <a class="header-anchor" href="#ユーティリティーソフトのインストール" aria-label="Permalink to “ユーティリティーソフトのインストール”">​</a></h2><p>ダウンロードしたドライバーのZIPファイル(<code>RISOUTSOFT_CD121M.zip</code>)を、右クリックして「すべて展開」を選択し、解凍してください。</p><p>解凍してできたフォルダの中にある(2階層中にある)<code>Windows</code>フォルダの中にある<code>setup.exe</code>をダブルクリックして、インストーラーを起動してください。 <img src="'+i+'" alt="setup.exe"></p><p>インストーラーに従って<code>次へ</code>をクリックして進めます。</p><p>使用許諾契約の条項に同意します。</p><p><code>セットアップタイプ</code>の画面では、そのまま<code>すべて</code>を選択した状態で、<code>次へ</code>をクリックしてください。</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p><code>理想集計アプリケーション</code>は今回は利用しないため、<code>カスタムセットアップ</code>よりインストールを除外しても構いません。 わからない場合は、上記の通り<code>すべて</code>を選択してインストールしてください。</p></div><p><code>インストール</code>をクリックして、インストールを開始し、<code>完了</code>の画面が表示されたらOKです。</p><p><code>理想USBメモリマネージャー</code>と<code>理想集計アプリケーション</code>の2つがインストールされていたら成功です。</p><h2 id="rufusのダウンロード" tabindex="-1">Rufusのダウンロード <a class="header-anchor" href="#rufusのダウンロード" aria-label="Permalink to “Rufusのダウンロード”">​</a></h2><p>次の手順で利用するRufusというUSBメモリのフォーマットツールを、ダウンロードします。</p><p>下記のリンクにアクセスします。 <a href="https://rufus.ie/ja/#download" target="_blank" rel="noreferrer">Rufus ダウンロード</a></p><p>Portable版のRufus<code>rufus-0.00p.exe</code>をクリックしてダウンロードしてください。<br><code>0.00</code>の部分は、ダウンロードする時点での最新バージョンの数字になります。 <img src="'+l+'" alt="Rufus"></p><p>ダウンロードフォルダに<code>rufus-0.00p.exe</code>がダウンロードされていたら成功です。</p>',38)])])}const k=o(n,[["render",h]]);export{I as __pageData,k as default};
